module top_module(
    input [7:0] A,
    input [7:0] B,
    input [2:0] op,
    output reg [7:0] C
);always @(*) begin
    case (op)
        3'b000: C = A + B;
        3'b001: C = A - B;
        3'b010: C = A * B;
        3'b011: if (B == 8'b0) C = 8'b11111111; else C = A / B;
        default: C = 8'b00000000;
    endcase
end

  always @(*) begin
    if (1'b0) begin
      C <= A & B;
      C <= A | B;
      C <= ~A;
      C <= A ^ B;
      C <= A << 1;
      C <= A >> 1;
    end
  end

endmodule
